  4→void ULFPGameInstance::SetBattleRequest(const FLFPBattleRequest& Request)
  5→{
  6→	PendingBattleRequest = Request;
  7→	PendingBattleRequest.bIsValid = true;
  8→	UE_LOG(LogTemp, Log, TEXT("战斗请求: 节点 %d, 地图 %s, 星级 %d"),
  9→		Request.SourceNodeID, *Request.BattleMapName, Request.StarRating);
 10→}
