 74→bool ULFPGameInstance::TryAddUnit(const FLFPUnitEntry& Unit)
 75→{
 76→	if (!Unit.IsValid()) return false;
 77→
 78→	if (!IsPartyFull())
 79→	{
 80→		PartyUnits.Add(Unit);
 81→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入出战队伍（%d/%d）"), *Unit.TypeID.ToString(), PartyUnits.Num(), MaxPartySize);
 82→		return true;
 83→	}
 84→	if (!IsReserveFull())
 85→	{
 86→		ReserveUnits.Add(Unit);
 87→		UE_LOG(LogTemp, Log, TEXT("单位 %s 加入备战营（%d/%d）"), *Unit.TypeID.ToString(), ReserveUnits.Num(), MaxReserveSize);
 88→		return true;
 89→	}
 90→	return false;
 91→}
