102→void ULFPGameInstance::ReplaceReserveUnit(int32 SlotIndex, const FLFPUnitEntry& NewUnit)
103→{
104→	if (ReserveUnits.IsValidIndex(SlotIndex))
105→	{
106→		UE_LOG(LogTemp, Log, TEXT("替换备战营槽 %d: %s → %s"), SlotIndex, *ReserveUnits[SlotIndex].TypeID.ToString(), *NewUnit.TypeID.ToString());
107→		ReserveUnits[SlotIndex] = NewUnit;
108→	}
109→}
