 20→void ALFPWorldMapPlayerController::BeginPlay()
 21→{
 22→	Super::BeginPlay();
 23→
 24→	// 设置输入模式
 25→	FInputModeGameAndUI InputMode;
 26→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 27→	InputMode.SetHideCursorDuringCapture(false);
 28→	SetInputMode(InputMode);
 29→	bShowMouseCursor = true;
 30→
 31→	// 设置 Enhanced Input
 32→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 33→	{
 34→		if (DefaultInputMapping)
 35→		{
 36→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 37→		}
 38→	}
 39→}
