 93→// ============== 输入处理 ==============
 94→
 95→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
 96→{
 97→	bIsDragging = false;
 98→	if (DragTime > DragThresholdTime)
 99→	{
100→		DragTime = 0.f;
101→		return;
102→	}
103→	DragTime = 0.f;
104→
105→	// 编辑器模式优先处理
106→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
107→	{
108→		// 射线检测点击的节点
109→		FHitResult HitResult;
110→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
111→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
112→
113→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
114→
115→		switch (CurrentTool)
116→		{
117→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
118→			{
119→				// 射线投射到 Z=0 平面获取世界坐标
120→				FVector WorldOrigin, WorldDirection;
121→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
122→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
123→				{
124→					float T = -WorldOrigin.Z / WorldDirection.Z;
125→					FVector HitPoint = WorldOrigin + WorldDirection * T;
126→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
127→				}
128→			}
129→			break;
130→
131→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
132→			if (ClickedNode)
133→			{
134→				WorldMapEditorComponent->SelectNode(ClickedNode);
135→				WorldMapEditorComponent->RemoveSelectedNode();
136→			}
137→			break;
138→
139→		case ELFPWorldMapEditorTool::WMET_MoveNode:
140→			if (ClickedNode)
141→			{
142→				WorldMapEditorComponent->SelectNode(ClickedNode);
143→			}
144→			else if (WorldMapEditorComponent->GetSelectedNode())
145→			{
146→				// 移动到点击位置
147→				FVector WorldOrigin, WorldDirection;
148→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
149→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
150→				{
151→					float T = -WorldOrigin.Z / WorldDirection.Z;
152→					FVector HitPoint = WorldOrigin + WorldDirection * T;
153→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
154→				}
155→			}
156→			break;
157→
158→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
159→			if (ClickedNode)
160→			{
161→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
162→			}
163→			break;
164→
165→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
166→			if (ClickedNode)
167→			{
168→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
169→			}
170→			break;
171→
172→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
173→			if (ClickedNode)
174→			{
175→				WorldMapEditorComponent->SelectNode(ClickedNode);
176→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
177→			}
178→			break;
179→
180→		default:
181→			break;
182→		}
183→		return;
184→	}
185→
186→	// 游戏模式：点击节点移动或进入
187→	FHitResult HitResult;
188→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
189→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
190→
191→	if (ClickedNode)
192→	{
193→		ALFPWorldMapManager* Manager = GetWorldMapManager();
194→		if (!Manager || !Manager->GetPlayerState()) return;
195→
196→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
197→
198→		// 点击当前节点 → 进入节点
199→		if (ClickedNode->NodeID == CurrentNodeID)
200→		{
201→			EnterNode(ClickedNode);
202→			return;
203→		}
204→
205→		// 点击相邻可达节点 → 移动
206→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
207→		if (ReachableIDs.Contains(ClickedNode->NodeID))
208→		{
209→			MoveToNode(ClickedNode);
210→		}
211→		else
212→		{
213→			// 不可达，只选中
214→			SelectNode(ClickedNode);
215→		}
216→	}
217→}
