329→void ALFPWorldMapPlayerController::MoveToNode(ALFPWorldMapNode* Node)
330→{
331→	if (!Node) return;
332→
333→	ALFPWorldMapManager* Manager = GetWorldMapManager();
334→	if (!Manager) return;
335→
336→	// 棋子移动中不允许操作
337→	if (Manager->IsPawnMoving()) return;
338→
339→	ClearReachableHighlight();
340→
341→	bool bMoved = Manager->MovePlayer(Node->NodeID);
342→	if (bMoved)
343→	{
344→		// 移动后显示新的可达节点
345→		ShowReachableNodes();
346→	}
