349→void ALFPWorldMapPlayerController::ShowReachableNodes()
350→{
351→	ClearReachableHighlight();
352→
353→	ALFPWorldMapManager* Manager = GetWorldMapManager();
354→	if (!Manager || !Manager->GetPlayerState()) return;
355→
356→	TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
357→	for (int32 NodeID : ReachableIDs)
358→	{
359→		if (ALFPWorldMapNode* Node = Manager->GetNode(NodeID))
360→		{
361→			Node->SetHighlighted(true);
362→			ReachableNodes.Add(Node);
363→		}
364→	}
365→}
