379→void ALFPWorldMapPlayerController::EnterNode(ALFPWorldMapNode* Node)
380→{
381→	if (!Node) return;
382→
383→	UE_LOG(LogTemp, Log, TEXT("进入节点 %d，类型: %d"), Node->NodeID, (int32)Node->NodeType);
384→
385→	switch (Node->NodeType)
386→	{
387→	case ELFPWorldNodeType::WNT_Battle:
388→	case ELFPWorldNodeType::WNT_Boss:
389→		EnterBattle(Node);
390→		break;
391→
392→	case ELFPWorldNodeType::WNT_Event:
393→		// TODO: 触发事件系统
394→		UE_LOG(LogTemp, Log, TEXT("事件节点 %d: EventID=%s"), Node->NodeID, *Node->EventID);
395→		break;
396→
397→	case ELFPWorldNodeType::WNT_Shop:
398→		// TODO: 打开商店 UI
399→		UE_LOG(LogTemp, Log, TEXT("商店节点 %d"), Node->NodeID);
400→		break;
401→
402→	case ELFPWorldNodeType::WNT_Town:
403→		// TODO: 进入城镇
404→		UE_LOG(LogTemp, Log, TEXT("城镇节点 %d"), Node->NodeID);
405→		break;
406→
407→	case ELFPWorldNodeType::WNT_QuestNPC:
408→		// TODO: 触发任务对话
409→		UE_LOG(LogTemp, Log, TEXT("任务NPC节点 %d"), Node->NodeID);
410→		break;
411→
412→	case ELFPWorldNodeType::WNT_SkillNode:
413→		// TODO: 打开技能树 UI
414→		UE_LOG(LogTemp, Log, TEXT("技能节点 %d"), Node->NodeID);
415→		break;
416→
417→	default:
418→		break;
419→	}
420→}
