468→ALFPWorldMapManager* ALFPWorldMapPlayerController::GetWorldMapManager() const
469→{
470→	if (!CachedWorldMapManager)
471→	{
472→		TArray<AActor*> Managers;
473→		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPWorldMapManager::StaticClass(), Managers);
474→		if (Managers.Num() > 0)
475→		{
476→			CachedWorldMapManager = Cast<ALFPWorldMapManager>(Managers[0]);
477→		}
478→	}
479→	return CachedWorldMapManager;
480→}
