  42→void ALFPTacticsPlayerController::BeginPlay()
  43→{
  44→    Super::BeginPlay();
  45→
  46→    // 设置输入模式
  47→    FInputModeGameAndUI InputMode;
  48→    InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
  49→    InputMode.SetHideCursorDuringCapture(false);
  50→    SetInputMode(InputMode);
  51→    bShowMouseCursor = true;
  52→
  53→    // 获取网格管理器
  54→    TArray<AActor*> FoundActors;
  55→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPHexGridManager::StaticClass(), FoundActors);
  56→    if (FoundActors.Num() > 0)
  57→    {
  58→        GridManager = Cast<ALFPHexGridManager>(FoundActors[0]);
  59→    }
  60→
  61→    // 设置Enhanced Input
  62→    if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
  63→    {
  64→        if (DefaultInputMapping)
  65→        {
  66→            Subsystem->AddMappingContext(DefaultInputMapping, 0);
  67→        }
  68→    }
  69→
  70→    // 初始化UI
  71→    if (TurnSpeedWidgetClass)
  72→    {
  73→        TurnSpeedListWidget = CreateWidget<ULFPTurnSpeedListWidget>(this, TurnSpeedWidgetClass);
  74→        if (TurnSpeedListWidget)
  75→        {
  76→            TurnSpeedListWidget->AddToViewport();
  77→            TurnSpeedListWidget->InitializeTurnOrder(); // 初始化单位顺序
  78→        }
  79→    }
  80→
  81→    // 绑定阶段变化委托
  82→    if (ALFPTurnManager* TurnManager = GetTurnManager())
  83→    {
  84→        TurnManager->OnPhaseChanged.AddDynamic(this, &ALFPTacticsPlayerController::OnPhaseChanged);
  85→
  86→        // StartGame() 在 GameMode::StartPlay() 中执行，早于 PlayerController::BeginPlay()
  87→        // 此时阶段已设置但未广播，需主动检查并触发布置阶段
  88→        if (TurnManager->GetCurrentPhase() == EBattlePhase::BP_Deployment)
  89→        {
  90→            OnDeploymentPhaseStarted();
  91→        }
  92→    }
  93→}
