 128→void ALFPTacticsPlayerController::Tick(float DeltaTime)
 129→{
 130→    Super::Tick(DeltaTime);
 131→
 132→    if (bIsDragging)
 133→    {
 134→        DragTime += DeltaTime;
 135→    }
 136→
 137→    // 布置阶段：更新预览单位跟随鼠标
 138→    if (bIsInDeployment && bIsPlacingUnit && PlacingUnitPreview)
 139→    {
 140→        FVector WorldOrigin, WorldDirection;
 141→        DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
 142→        if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
 143→        {
 144→            float T = -WorldOrigin.Z / WorldDirection.Z;
 145→            FVector HitPoint = WorldOrigin + WorldDirection * T;
 146→            PlacingUnitPreview->SetActorLocation(FVector(HitPoint.X, HitPoint.Y, 50.f));
 147→        }
 148→    }
 149→
 150→    // 更新相机位置
 151→    if (GridManager)
 152→    {
 153→        FVector CameraLocation = GridManager->GetActorLocation() + CameraOffset;
 154→        FRotator CameraRotation(CameraRotationPitchAngle, CameraRotationYawAngle, 0);
 155→        SetControlRotation(CameraRotation);
 156→
 157→        // 计算相机位置偏移
 158→        FVector DirectionOffset = CameraRotation.Vector() * CurrentZoom;
 159→        DirectionOffset.Z = CurrentZoom * 0.5f; // 高度由缩放比例决定
 160→
 161→        // 设置相机位置
 162→        APawn* ControlledPawn = GetPawn();
 163→        if (ControlledPawn)
 164→        {
 165→            FVector TargetLocation = CameraLocation + DirectionOffset;
 166→            ControlledPawn->SetActorLocation(FMath::VInterpTo(
 167→                ControlledPawn->GetActorLocation(),
 168→                TargetLocation,
 169→                DeltaTime,
 170→                5.0f // 插值速度
 171→            ));
 172→        }
 173→
 174→        // 获取鼠标位置
 175→        float MouseX, MouseY;
 176→        if (GetMousePosition(MouseX, MouseY))
 177→        {
 178→            FVector2D ScreenPosition(MouseX, MouseY);
 179→            // 获取光标下的六边形Tile
 180→            ALFPHexTile* HoveredTile = GridManager->GetHexTileUnderCursor(ScreenPosition, this);
 181→            // 处理鼠标悬停逻辑
 182→            if (HoveredTile != LastHoveredTile)
 183→            {
 184→                if (LastHoveredTile)
 185→                {
 186→                    //LastHoveredTile->OnMouseExit();
 187→                }
 188→
 189→                if (HoveredTile)
 190→                {
 191→                    SelectTile(HoveredTile);
 192→                    //HoveredTile->OnMouseEnter();
 193→                }
 194→
 195→                LastHoveredTile = HoveredTile;
 196→            }
 197→
 198→            // 敌人计划预览：检测悬停的格子上是否有带行动计划的敌人
 199→            if (CachedBattlePhase == EBattlePhase::BP_EnemyPlanning || CachedBattlePhase == EBattlePhase::BP_ActionPhase)
 200→            {
 201→                ALFPTacticsUnit* HoveredEnemy = nullptr;
 202→                if (LastHoveredTile)
 203→                {
 204→                    ALFPTacticsUnit* UnitOnTile = LastHoveredTile->GetUnitOnTile();
 205→                    if (UnitOnTile && UnitOnTile->IsEnemy() && UnitOnTile->HasActionPlan())
 206→                    {
 207→                        HoveredEnemy = UnitOnTile;
 208→                    }
 209→                }
 210→
 211→                if (HoveredEnemy && HoveredEnemy != PreviewedEnemy)
 212→                {
 213→                    HideEnemyPlanPreview();
 214→                    ShowEnemyPlanPreview(HoveredEnemy);
 215→                }
 216→                else if (!HoveredEnemy && PreviewedEnemy)
 217→                {
 218→                    HideEnemyPlanPreview();
 219→                }
 220→            }
 221→        }
 222→    }
 223→
 224→    // 更新地图视觉效果
 225→    if (LastControlState != CurrentControlState)
 226→    {
 227→        switch (CurrentControlState)
 228→        {
 229→        case EPlayControlState::MoveState:
 230→            break;
 231→        case EPlayControlState::SkillReleaseState:
 232→            break;
 233→        default:
 234→            break;
 235→        }
 236→    }
 237→}
