 300→void ALFPTacticsPlayerController::OnConfirmAction(const FInputActionValue& Value)
 301→{
 302→    bIsDragging = false;
 303→    if (DragTime > DragThresholdTime)
 304→    {
 305→        DragTime = 0.f;
 306→        return;
 307→    }
 308→    DragTime = 0.f;
 309→
 310→    // 布置阶段优先处理
 311→    if (bIsInDeployment)
 312→    {
 313→        if (bIsPlacingUnit)
 314→        {
 315→            // 正在放置单位：检测是否点击了空闲出生点
 316→            if (LastHoveredTile && PlayerSpawnTiles.Contains(LastHoveredTile)
 317→                && !LastHoveredTile->IsOccupied())
 318→            {
 319→                PlaceUnit(LastHoveredTile);
 320→            }
 321→        }
 322→        else
 323→        {
 324→            // 不在放置模式：检测是否点击了已放置的单位（拾起）
 325→            FHitResult HitResult;
 326→            GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
 327→            ALFPTacticsUnit* ClickedUnit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 328→            if (ClickedUnit && DeployedUnits.Contains(ClickedUnit))
 329→            {
 330→                PickupDeployedUnit(ClickedUnit);
 331→            }
 332→        }
 333→        return;
 334→    }
 335→
 336→    // 编辑器模式优先处理
 337→    if (MapEditorComponent && MapEditorComponent->IsEditorActive())
 338→    {
 339→        if (LastHoveredTile)
 340→        {
 341→            MapEditorComponent->ApplyToolToTile(LastHoveredTile);
 342→        }
 343→        else if (GridManager && MapEditorComponent->GetCurrentTool() == ELFPMapEditorTool::MET_AddTile)
 344→        {
 345→            // 对空白区域添加格子：射线投射到 Z=0 平面计算坐标
 346→            FVector WorldOrigin, WorldDirection;
 347→            DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
 348→            if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
 349→            {
 350→                float T = -WorldOrigin.Z / WorldDirection.Z;
 351→                FVector HitPoint = WorldOrigin + WorldDirection * T;
 352→                FVector2D LocalLoc(
 353→                    HitPoint.X - GridManager->GetActorLocation().X,
 354→                    HitPoint.Y - GridManager->GetActorLocation().Y
 355→                );
 356→                FLFPHexCoordinates Coord = FLFPHexCoordinates::FromWorldLocation(
 357→                    LocalLoc, GridManager->GetHexSize(), GridManager->GetVerticalScale());
 358→                MapEditorComponent->ApplyToolToCoord(Coord.Q, Coord.R);
 359→            }
 360→        }
 361→        return;
 362→    }
 363→
 364→    if (SelectedUnit && SelectedTile)
 365→    {
 366→        if (bIsAttacking)
 367→        {
 368→            // 获取鼠标位置
 369→            float MouseX, MouseY;
 370→            GetMousePosition(MouseX, MouseY);
 371→            FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
 372→
 373→            FHitResult HitResult;
 374→            GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
 375→
 376→            if (HitResult.bBlockingHit)
 377→            {
 378→                // 尝试选中单位
 379→                ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 380→                if (Unit)
 381→                {
 382→                    AttackTarget(SelectedUnit, Unit);
 383→                    return;
 384→                }
 385→            }
 386→        }
 387→        else if (bIsReleaseSkill && CurrentSelectedSkill)
 388→        {
 389→            ExecuteSkill(CurrentSelectedSkill);
 390→        }
 391→        else
 392→        {
 393→            ConfirmMove();
 394→        }
 395→    }
 396→    else if (SelectedUnit)
 397→    {
 398→        // 如果没有选中目标格子，显示可移动范围
 399→        //ShowMovementRange(true);
 400→    }
 401→}
