 486→void ALFPTacticsPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
 487→{
 488→    if (!bIsDragging) return;
 489→
 490→    // 获取当前鼠标位置
 491→    FVector2D CurrentMousePosition;
 492→    GetMousePosition(CurrentMousePosition.X, CurrentMousePosition.Y);
 493→
 494→    // 计算鼠标移动偏移
 495→    FVector2D MouseDelta = CurrentMousePosition - DragStartPosition;
 496→
 497→    // 反转Y轴（屏幕Y轴向下，世界Y轴向上）
 498→    MouseDelta.Y = -MouseDelta.Y;
 499→
 500→    // 计算移动方向（基于当前相机旋转）
 501→    FRotator CameraRotation(0, CameraRotationYawAngle, 0);
 502→    FVector Right = CameraRotation.RotateVector(FVector::RightVector);
 503→    FVector Forward = CameraRotation.RotateVector(FVector::ForwardVector);
 504→
 505→    // 计算移动偏移
 506→    FVector PanDirection = (Right * -MouseDelta.X) + (Forward * -MouseDelta.Y);
 507→    //PanDirection.Normalize();
 508→
 509→    // 应用移动
 510→    CameraOffset += PanDirection * CameraDragSpeed;
 511→
 512→    // 更新起始位置为当前位置
 513→    DragStartPosition = CurrentMousePosition;
 514→}
