 747→void ALFPTacticsPlayerController::SkipTurn(ALFPTacticsUnit* Unit)
 748→{
 749→    if (!Unit || !Unit->CanAct()) return;
 750→
 751→    // 标记为已行动
 752→    Unit->SetHasActed(true);
 753→
 754→    // 可选：消耗1个行动力作为跳过代价
 755→    // Unit->ConsumeMovePoints(1);
