 914→void ALFPTacticsPlayerController::OnPhaseChanged(EBattlePhase NewPhase)
 915→{
 916→    CachedBattlePhase = NewPhase;
 917→    UE_LOG(LogTemp, Log, TEXT("OnPhaseChanged:=%d"), NewPhase);
 918→    // 阶段切换时清理预览状态
 919→    HideEnemyPlanPreview();
 920→
 921→    switch (NewPhase)
 922→    {
 923→    case EBattlePhase::BP_Deployment:
 924→        OnDeploymentPhaseStarted();
 925→        break;
 926→
 927→    case EBattlePhase::BP_EnemyPlanning:
 928→        // 敌人规划阶段：隐藏技能选择UI
 929→        HideSkillSelection();
 930→        break;
 931→
 932→    case EBattlePhase::BP_ActionPhase:
 933→        // 行动阶段：恢复正常
 934→        break;
 935→
 936→    case EBattlePhase::BP_RoundEnd:
 937→        break;
 938→    }
 939→}
