1025→void ALFPTacticsPlayerController::StartPlacingUnit(int32 PartyIndex)
1026→{
1027→    // 如果正在放置其他单位，先取消
1028→    if (bIsPlacingUnit)
1029→    {
1030→        CancelPlacing();
1031→    }
1032→
1033→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
1034→    if (!GI || !GI->UnitRegistry) return;
1035→    if (!GI->PartyUnits.IsValidIndex(PartyIndex)) return;
1036→
1037→    // 如果该单位已经放置，先拾起
1038→    if (DeployedUnits.IsValidIndex(PartyIndex) && DeployedUnits[PartyIndex])
1039→    {
1040→        PickupDeployedUnit(DeployedUnits[PartyIndex]);
1041→    }
1042→
1043→    const FLFPUnitEntry& Entry = GI->PartyUnits[PartyIndex];
1044→    TSubclassOf<ALFPTacticsUnit> UnitClass = GI->UnitRegistry->GetUnitClass(Entry.TypeID);
1045→    if (!UnitClass) return;
1046→
1047→    // 在鼠标位置生成预览单位
1048→    FVector UnitSpawnLoc = FVector(0, 0, 50.f);
1049→    FActorSpawnParameters SpawnParams;
1050→    PlacingUnitPreview = GetWorld()->SpawnActor<ALFPTacticsUnit>(UnitClass, UnitSpawnLoc, FRotator::ZeroRotator, SpawnParams);
1051→
1052→    if (PlacingUnitPreview)
1053→    {
1054→        PlacingUnitPreview->Affiliation = EUnitAffiliation::UA_Player;
1055→        PlacingUnitPreview->UnitTypeID = Entry.TypeID;
1056→        PlacingUnitPreview->UnitTier = Entry.Tier;
1057→    }
1058→
1059→    PlacingPartyIndex = PartyIndex;
1060→    bIsPlacingUnit = true;
1061→
1062→    if (DeploymentWidget)
1063→    {
1064→        DeploymentWidget->MarkUnitSelecting(PartyIndex);
1065→    }
1066→
1067→    UE_LOG(LogTemp, Log, TEXT("开始放置单位 %s（索引 %d）"), *Entry.TypeID.ToString(), PartyIndex);
1068→}
