1103→void ALFPTacticsPlayerController::CancelPlacing()
1104→{
1105→    if (PlacingUnitPreview)
1106→    {
1107→        PlacingUnitPreview->Destroy();
1108→        PlacingUnitPreview = nullptr;
1109→    }
1110→
1111→    PlacingPartyIndex = -1;
1112→    bIsPlacingUnit = false;
1113→}
