1115→void ALFPTacticsPlayerController::PickupDeployedUnit(ALFPTacticsUnit* Unit)
1116→{
1117→    if (!Unit) return;
1118→
1119→    // 找到对应的 PartyIndex
1120→    int32 FoundIndex = DeployedUnits.Find(Unit);
1121→    if (FoundIndex == INDEX_NONE) return;
1122→
1123→    // 清除格子占用
1124→    ALFPHexTile* OldTile = Unit->GetCurrentTile();
1125→    if (OldTile)
1126→    {
1127→        OldTile->SetIsOccupied(false);
1128→        OldTile->SetUnitOnTile(nullptr);
1129→    }
1130→
1131→    // 设置为跟随鼠标的预览
1132→    PlacingUnitPreview = Unit;
1133→    PlacingPartyIndex = FoundIndex;
1134→    bIsPlacingUnit = true;
1135→
1136→    // 清除已布置记录
1137→    DeployedUnits[FoundIndex] = nullptr;
1138→
1139→    // 更新 UI
1140→    if (DeploymentWidget)
1141→    {
1142→        DeploymentWidget->MarkUnitPlaced(FoundIndex, false);
1143→    }
1144→
1145→    UE_LOG(LogTemp, Log, TEXT("拾起已放置的单位（索引 %d）"), FoundIndex);
1146→}
